INSERT INTO `lnj_posts` VALUES (5,3,'2017-01-30 10:34:43','2017-01-30 10:34:43','','Collections','','publish','closed','closed','','collections','','','2024-10-18 05:37:54','2024-10-18 05:37:54','',0,'http://lnjdenim.in/?page_id=5',45,'page','',0),(6,3,'2017-01-30 10:34:43','2017-01-30 10:34:43','','Collections','','inherit','closed','closed','','5-revision-v1','','','2017-01-30 10:34:43','2017-01-30 10:34:43','',5,'http://lnjdenim.in/index.php/2017/01/30/5-revision-v1/',0,'revision','',0),(7,3,'2017-01-30 10:35:16','2017-01-30 10:35:16','<p>\r\nWe support our clients’ creativity with state-of-the art machinery. LNJ Denim employs skilled textile engineers to operate our world-class equipment. As safety is our priority, our facilities are well-lit, airconditioned and clean. We adhere to strict safety standards and our factories have achieved OHSAS18001 and SA-8000 certificates. We at the LNJ denim plant, use state-of-the-art machinery to create your fabric dreams into reality.\r\n\r\n</p>','Plant','','publish','closed','closed','','technology-innovation','','','2021-10-28 05:39:11','2021-10-28 05:39:11','',0,'http://lnjdenim.in/?page_id=7',65,'page','',0),(8,3,'2017-01-30 10:35:16','2017-01-30 10:35:16','','Technology & Innovation','','inherit','closed','closed','','7-revision-v1','','','2017-01-30 10:35:16','2017-01-30 10:35:16','',7,'http://lnjdenim.in/index.php/2017/01/30/7-revision-v1/',0,'revision','',0),(9,3,'2017-01-30 10:36:35','2017-01-30 10:36:35','LNJ Denim is committed to processes and technologies that help keep our environment green and our business sustainable.\r\nEucalyptus from sustainably managed plantations such as this one provide cellulose for lyocell, one of many fibres we can utilise in your denim.','Sustainability','','publish','closed','closed','','sustainability','','','2021-10-28 05:42:03','2021-10-28 05:42:03','',0,'http://lnjdenim.in/?page_id=9',60,'page','',0),(10,3,'2017-01-30 10:36:35','2017-01-30 10:36:35','','Sustainability','','inhe